import React from 'react';

const EditorToolbar = ({ onFormat }) => {
  const insertText = (before, after, selection) => {
    const textarea = document.querySelector('.markdown-editor');
    if (!textarea) return;

    const start = selection ? selection.start : textarea.selectionStart;
    const end = selection ? selection.end : textarea.selectionEnd;

    const text = textarea.value;
    const newText = text.substring(0, start) + before + text.substring(start, end) + after + text.substring(end);

    textarea.value = newText;
    textarea.focus();

    // Restore cursor position
    const newCursorPos = start + before.length;
    textarea.setSelectionRange(newCursorPos, newCursorPos);
  };

  const wrapSelection = (before, after) => {
    const textarea = document.querySelector('.markdown-editor');
    if (!textarea) return;

    const selection = {
      start: textarea.selectionStart,
      end: textarea.selectionEnd
    };

    insertText(before, after, selection);
  };

  const handleBold = () => wrapSelection('**', '**');
  const handleItalic = () => wrapSelection('*', '*');
  const handleHeading = (level) => wrapSelection('#'.repeat(level) + ' ', '');
  const handleCode = () => wrapSelection('`', '`');
  const handleList = (ordered) => {
    const textarea = document.querySelector('.markdown-editor');
    if (!textarea) return;

    const selection = {
      start: textarea.selectionStart,
      end: textarea.selectionEnd
    };

    const text = textarea.value;
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const selectedText = text.substring(start, end);

    // Get the current line
    const lines = text.substring(0, start).split('\n');
    const currentLine = lines[lines.length - 1] || '';
    const indentation = currentLine.match(/^\s*/)[0] || '';

    if (ordered) {
      const newList = selectedText.split('\n').map((line, index) => 
        `${indentation}${index + 1}. ${line.trim()}`
      ).join('\n');
      insertText(newList, '', selection);
    } else {
      const newList = selectedText.split('\n').map(line => 
        `${indentation}- ${line.trim()}`
      ).join('\n');
      insertText(newList, '', selection);
    }
  };

  return (
    <div className="editor-toolbar">
      <div className="toolbar-group">
        <button
          className="toolbar-btn"
          onClick={handleBold}
          title="Bold (Ctrl+B)"
        >
          <strong>B</strong>
        </button>
        <button
          className="toolbar-btn"
          onClick={handleItalic}
          title="Italic (Ctrl+I)"
        >
          <em>I</em>
        </button>
      </div>

      <div className="toolbar-group">
        <button
          className="toolbar-btn"
          onClick={() => handleHeading(1)}
          title="Heading 1 (Ctrl+1)"
        >
          H1
        </button>
        <button
          className="toolbar-btn"
          onClick={() => handleHeading(2)}
          title="Heading 2 (Ctrl+2)"
        >
          H2
        </button>
        <button
          className="toolbar-btn"
          onClick={() => handleHeading(3)}
          title="Heading 3 (Ctrl+3)"
        >
          H3
        </button>
      </div>

      <div className="toolbar-group">
        <button
          className="toolbar-btn"
          onClick={() => handleList(false)}
          title="Bullet List (Ctrl+L)"
        >
          • List
        </button>
        <button
          className="toolbar-btn"
          onClick={() => handleList(true)}
          title="Numbered List (Ctrl+Shift+L)"
        >
          1. List
        </button>
        <button
          className="toolbar-btn"
          onClick={handleCode}
          title="Code (Ctrl+K)"
        >
          {'</>'}
        </button>
      </div>
    </div>
  );
};

export default EditorToolbar;
